module low_pass_filter (
  input clk,
  input rst,
  input [7:0] sample_in,
  output [7:0] filtered_out
);
  reg [7:0] prev_sample;

  always @(posedge clk) begin
    if (rst) prev_sample <= 0;
    else prev_sample <= sample_in;
  end

  assign filtered_out = (sample_in + prev_sample) >> 1;
endmodule

module filter_chain (
  input clock,
  input reset,
  input [7:0] input_sample,
  output [7:0] output_sample
);
  low_pass_filter filter_inst (
    .clk(clock),
    .rst(reset),
    .sample_in(input_sample)
  );
endmodule

